    ['Blood of Heroes'] = {
        id = 52,
        start_npc = 'Excenmille',
        start_zone = 'Xarcabard (S)',
        start_pos = nil,
        description = 'Count Aurchiat lies dead, felled in an Orcish ambush that has left the Cardinal Stags severely weakened deep in the heart of enemy territory. The key to survival lies in a joint operation with the Iron Rams...',
        reward = 'Ram Staff',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = 'House Aurchiat Retainer',
        repeatable = nil,
        previous = {'Songbirds in a Snowstorm'},
        next = {'Chasing Shadows'},
        requirements = nil,
        walkthrough = '1. Examine the Animal Spoor in Xarcabard (S) at (J-9).\n   - Close to the Beaucedine Glacier (S) zone.\n   - Make sure to grab the Xarcabard (S) Home Point at (H-9) if you haven\'t yet.\n2. Examine the Wheel Rut at (I-9), early in the dead-end tunnel at the southern part of the grid.\n3. Examine the Animal Spoor at (J-9) again for a [Key Item] Vial of military prism powder.\n4. Examine the Forbidding Portal door in the northwest corner of (I-7) for a cutscene.  Examine it again to enter the Battlefield.\nIn this BC you must fight 2 Bloodwing Deathrainers (BLM), 4 Bloodwing Maimers (WAR), a Bugard named Gherrmoga, and Kingslayer Doggvdegg (PLD).\n5. You will be assisted by Excenmille; should he fall, the battle will instantly end in failure. Do not delay too long at the beginning, or he might run in and get himself killed.\n   - Excenmille will occasionally use a skill called Stag\'s Cry that will give party members in range a temporary attack boost and magic attack bonus.\n   - Excenmille will also do a weaponskill called Songbird Swoop that does damage.\n6. Defeating Kingslayer Doggvdegg will end the fight regardless of the other NMs\' health; however, his death may be prolonged due to Invincible.\n   - A good strategy is to have someone kite Kingslayer Doggvdegg, and Elemental Seal + Sleepga the BLMs and WARs.  Fight the the Bugard, then the BLMs, then the WARs, then finally fight Kingslayer Doggvdegg himself.\n   - Kingslayer Doggvdegg will use Invincible and will occasionally gain a Stoneskin effect.\n   - If you lose the battlefield, wait until the next Vana\'diel day and return to the Animal Spoor to receive another [Key Item] Vial of military prism powder.\nAfter the fight, examine the Wheel Rut back at (I-9) for a cutscene that ends the quest and your reward.\nIf you are working on missions then return to Fate in Haze.',
        notes = nil,
    },
    ['Bonds That Never Die'] = {
        id = 45,
        start_npc = 'Cyranuce',
        start_zone = 'Pashhow Marshlands (S)',
        start_pos = nil,
        description = 'Determined not to let Machegue\'s death be in vain, Excenmille has disobeyed his father\'s direct orders and embarked on a solitary mission to slay the behemoth. Follow him to Jugner Forest and ensure his safety!',
        reward = 'Behemoth Horn',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = 'Honorary Knight of the Cardinal Stag',
        repeatable = nil,
        previous = {'The Price of Valor'},
        next = {'Songbirds in a Snowstorm'},
        requirements = {
            {name = 'Hatchets, for logging.', count = 1},
        },
        walkthrough = '1. Talk to Rholont in Southern San d\'Oria (S) (E-7) to receive a [Key Item] Letter to Count Aurchiat.\n   - May have to speak to Rholont more than once to trigger cutscene.\n   - If you don\'t have Hatchets, buy them from Geltpix at (M-6) now to save time, because you\'ll need them for this quest.\n2. Head back to Pashhow Marshlands (S) and examine the Shimmering Pondweed at (G-6) again for a cutscene.\n   - Using the Campaign teleport will most likely be your fastest way here.\n   - The next closest method is teleporting to the Survival Guide in Rolanberry Fields (S), which will put you right at the top zone line for Pashhow Marshlands (S).\n   - The quest will now be flagged in your log.\n3. Travel to Jugner Forest (S) and examine the Overgrown Mushrooms at (F-10) for a cutscene. (They are on the pathway.)\n   - Recall ring: Jugner or Recall-Jugner will get you close to where you are going the fastest. The Survival Guide is also a good option.\n   - Note: Have at least one open inventory slot or you will have to rewatch the entire CS again.\n4. Use Hatchets on Logging Points in the area until you receive a [Key Item] Length of Jugner Ivy.\n   - The chance of getting the Length of Jugner Ivy from a logging point is high, but not 100%.\n   - If you\'re struggling to get it, fill your inventory completely and the game will be forced to give you the key item.\n   - Logging points are around (F-7) (F-10) (J-6) and (J/K - 10/11); see the map on the right.\n5. Return to the Overgrown Mushrooms at (F-10) in Jugner Forest (S) for another cutscene.\n6. Travel to the lower right corner of (F-7) and check the Mossy Stump for a cutscene.\n7. After the cutscene, inspect the Mossy Stump again to enter a battlefield against a Young Behemoth.\n   - See the Discussion page for testimonials and boss-related information.\n8. After you have cleared the battlefield, report to Rongelouts N Distaud (S) (I-9) in Southern San d\'Oria (S) to receive your reward.\n   - Zone into Southern San d\'Oria (S) from East Ronfaure (S) after a game day for a cutscene. (Not needed to progress Crossroads of Time.)\nIf you are working on missions then return to Crossroads of Time.\nNote: You will need to wait until the next Vana\'diel day, have zoned, and be on the quest Fate in Haze to continue to progress your nation\'s story after completing this quest.',
        notes = nil,
    },
    ['Bonds of Mythril'] = {
        id = 59,
        start_npc = 'Volker',
        start_zone = 'Castle Zvahl Baileys (S)',
        start_pos = nil,
        description = 'Fighting alongside ghastly demons one moment, risking her life to defend you the next... What is Captain Klara\'s true connection to the armies of shadow? Return to the site of your confrontation, that long sought-after truths may at last be revealed!',
        reward = 'Excelsis Ring',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = 'Temperer of Mythril',
        repeatable = nil,
        previous = {'The Truth Lies Hid'},
        next = nil,
        requirements = nil,
        walkthrough = '1. Zone into Castle Zvahl Baileys (S) from Castle Zvahl Keep (S) for a cutscene.\n2. Examine the ??? in the south-west room (G-9) on the third map of Castle Zvahl Keep (S) (the map with the teleporters) for a cutscene.\n3. Drop back down in the third map main room and kill all four imps.  All four must be killed after the previous cutscene.\n   - If you kill any of the four imps prior to this cut scene, you will have to wait for them to re-spawn and kill them again.\n4. Examine the ??? again to spawn a NM called Gargouille Warden, defeat it and examine the ??? again to receive the [Key Item]Zvahl passkey.\n   - Gargouille Warden is resistant to magical attacks, and has an en-stun effect on its melee hits.\n   - You have to kill all four imps in the central room in order to spawn the Gargouille Warden.\n5. Enter the Throne Room (S), and examine the Throne Room door for a cutscene.\n6. Examine the Throne Room door again to enter the BC fight.\n   - When you enter the BC, your initial opponent will be a humanoid who uses standard sword weaponskills:\n     - In addition, your opponent will use the AoE weaponskills Temblor Blade with the additional effect of petrify and Darkling Blade which is damage, knockback, and additional effect of curse.\n   - You will be joined in this part of the battle by Zeid.  Should Zeid fall, the battle will be over.\n   - After defeating your first opponent, you will have to defeat Marquis Amon.\n     - Marquis Amon is a BLM Demon who uses a scythe.  He has access to tier 3 AoE elemental magic.\n     - Marquis Amon has a weaponskill that will draw everyone in, wipe shadows, and inflict Doom.  The doom effect can be blocked by wearing the Sanctus Rosary from the previous mission.  The doom effect can also be stunned.\n7. Speak to Gentle Tiger in Bastok Markets (S) at (H-6) for a cutscene and your reward.\n   - Speak to Gentle Tiger again to learn Trust Magic: Klara if you possess the [Key Item] Bundle of half-inscribed scrolls.\nIf you are working on missions then return to Adieu, Lilisette.',
        notes = nil,
    },
    ['Boy and the Beast'] = {
        id = 24,
        start_npc = 'Raustigne',
        start_zone = 'Southern San d\'Oria',
        start_pos = 'I-7',
        description = 'Klythios the Gigas has hurt his leg during an epic fish-off with Excenmille. Make haste and go gather the correct healing herb to treat the injury.',
        reward = 'Carbon Fishing Rod',
        fame = 'Crystal War',
        fame_level = nil,
