        id = 73,
        start_npc = 'Walk of Echoes',
        start_zone = nil,
        start_pos = nil,
        description = 'A familiar, enigmatic voice has asked you to travel to Ronfaure, Jugner Forest, and Beaucedine Glacier in the Shadowreign Era and gather latent energies present there.',
        reward = 'Choice of:\nPact with Cait Sith\n10,000 Gil',
