    ['Healing Herbs'] = {
        id = 3,
        start_npc = 'Rhinostery',
        start_zone = 'Windurst Waters',
        start_pos = 'J-8',
        description = 'Maju-Naju\'s research has ground to a halt. He needs research materials that are hard to find in this day and age...',
        reward = 'Tincture',
        fame = nil,
        fame_level = nil,
        title = 'None',
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Begin the quest by checking the Rhinostery door in Windurst Waters (S) at (J-8) second map. There will be cutscene dialogue between Dantie-Corantie and Maju-Naju.\n   - There are two Rhinostery doors, the one on the left activates this quest.\n2. Go to the present Windurst Waters and approach the door of the Rhinostery for a cutscene. You will be given a [Key Item] "The Healing Herb".\n3. Go back to the past Rhinostery and check the door for another cutscene.\n4. Go to Grauberg (S) and touch the ??? located near center of (H-13) for a [Key Item] Fireblossom.\n5. Go back to Windurst Waters (S) and check the Rhinostery door once again for a cutscene.\n6. Wait until the next game day and check the Rhinostery door once again for a cutscene.\n7. Wait once again for the next game day. Check the Rhinostery door once more for a final cutscene and your reward, in form of a Tincture, as well as the [Key Item] "The Healing Herb" once again.\n8. Go back to the present Windurst Waters and check the Rhinostery door for an extra cut scene. The [Key Item] "The Healing Herb" will be taken from you.',
        notes = nil,
    },
    ['Her Memories: Carnelian/Azure/Verdure'] = {
        id = 69,
        start_npc = nil,
        start_zone = 'Southern San d\'Oria (S), Bastok Markets (S), or Windurst Waters (S)',
        start_pos = nil,
        description = 'These are mutually exclusive quests — only one can be completed per character. Lilisette sought admission into one of three nations\' military forces. Follow her footsteps to discover whether her attempt was successful.',
        reward = '[Key Item] Large memory fragment',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Her Memories'},
        next = nil,
        requirements = nil,
        walkthrough = 'Only one of these quests can be completed per character. Choose one:\n\n[Carnelian Footfalls — San d\'Oria]\n1. Enter Southern San d\'Oria (S) from East Ronfaure (S).\n2. Speak to Mainchelite in Southern San d\'Oria (S) at (I-9).\n3. Zone into East Ronfaure (S) from Southern San d\'Oria (S) for a cut-scene, then examine the ??? spots at:\n   - (H-8) in a hole of dirt, just north-east of the Fort.\n   - (I-8) at the base of the waterfall, north-west corner.\n   - (J-7) just south of a tree, north-west corner.\n4. Speak to Mainchelite in Southern San d\'Oria (S) to receive the [Key Item] Large memory fragment.\n\n[Azure Footfalls — Bastok]\n1. Zone into Bastok Markets (S) from North Gustaberg (S).\n2. Speak to Adelbrecht in Bastok Markets (S) at (E-8).\n3. Speak to Gebhardt at North Gustaberg (S) (I-6), the first level of Zegham Hill.\n4. Speak to Roderich at North Gustaberg (S) (E-11).\n5. Examine the Barricade in North Gustaberg (S) (E-7).\n6. Speak to Adelbrecht in Bastok Markets (S) to receive the [Key Item] Large memory fragment.\n\n[Verdure Footfalls — Windurst]\n1. Zone into Windurst Waters (S) from West Sarutabaruta (S).\n2. Speak to Miah Riyuh in Windurst Waters (S) at (H-9) (North map).\n3. Zone into West Sarutabaruta (S) and examine the Sealed Entrances for the towers at (F-4), (F-11), and (J-8).\n4. Speak to Miah Riyuh in Windurst Waters (S) to receive the [Key Item] Large memory fragment.',
        notes = nil,
    },
