    ['Her Memories: Of Malign Maladies'] = {
        id = 72,
        start_npc = 'Amaura',
        start_zone = 'Southern San d\'Oria',
        start_pos = nil,
        description = 'Lilisette had embarked on a frenetic journey to find a cure for Sir Ragelise\'s affliction. Has the passage of time seen the discovery of a remedy?',
        reward = '[Key Item] Large memory fragment',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Her Memories'},
        next = nil,
        requirements = {
            {name = 'Philosopher\'s Stone', count = 1},
        },
        walkthrough = '1. Speak to Amaura in Southern San d\'Oria (Home Point #4) (G-6).\n2. Speak to Monberaux in Upper Jeuno (Home Point #3) (G-10).\n3. Examine the Library Book on the east wall of the Optistery in Windurst Waters North (Home Point #1) (G-7).\n4. Trade a Philosopher\'s Stone to Fey Blossoms at Witchfire Glen in Grauberg (S) (F-5).\n   - Use the Survival Guide to travel to Grauberg (S), or take the C.A (Campaign Arbiter) Warp to Grauberg (S) and run NW to (F-5).\n     - The C.A (Campaign Arbiter) Warp will bring you closest to reach Witchfire Glen for this objective if you have little to no progress with Voidwatch.\n   - Shortcut If you have completed the Voidwatch quest Glimmer of Hope:\n     - Use a Survival Guide to travel to Pashhow Marshlands (S).\n     - Enter Walk of Echoes via the Veridical Conflux (J-9).\n     - Activate the center Conflux in this area of the Walk to quickly teleport to Witchfire Glen in Grauberg (S).\n   - If you have obtained the [Key Item] Lightsworm are currently on an RoV mission involving the Walk of Echoes, you may use any blue ??? near the Cavernous Maws surrounding Jeuno (past or present) to zone in as a shortcut. (Unfortunately, this may not work if you are on Rhapsodies of Vanadiel Mission 2-18 (Somber Dreams). See the Lightsworm page for additional details.)\n     - Taking the Batallia Downs Survival Guide puts you right next to a Cavernous Maw for you to utilize your Lightsworm to travel straight to Walk of Echoes in this way, from which you can also exit to Witchfire Glen.\n5. Zone out and wait a game day.\n   - You can zone out via the Veridical Conflux if you have it unlocked.\n6. After zoning and waiting, examine the Fey Blossoms again to receive the [Key Item] Fey stone.\n7. Speak to Raustigne in Southern San d\'Oria (S) (I-7) to receive the [Key Item] Large memory fragment.',
        notes = nil,
    },
    ['Her Memories: Old Bean'] = {
