        description = 'The notorious assassin Darksteel Hurricane has returned in full force to wreak havoc on the embattled Republic of Bastok. Assist the Mythril Musketeers to locate and apprehend the blood-thirsty criminal before more lives are lost.',
        reward = 'Goblin Belt',
