    ['Sins of the Mothers'] = {
        id = 53,
        start_npc = 'Lehko Habhoka',
        start_zone = 'Windurst Waters (S)',
        start_pos = nil,
        description = 'A state of emergency has been declared as the Shadow Lord\'s army marches inexorably toward the Federation. In the midst of the turmoil, Lehko Habhoka has summoned you to Heavens Tower with a task of particular import...',
        reward = 'Kitty Rod',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'The Forbidden Path'},
        next = {'Howl from the Heavens'},
        requirements = nil,
        walkthrough = '1. Speak to Dhea Prandoleh (H-10) for a CS, then to Velda-Galda (K-9) for another CS.\n2. Head to Fort Karugo-Narugo (S) and check the Stone monument at (E-7) (outside, Map 1).\n3. Check the Succulent Cactus at (F-5) for a [Key Item]Succulent dragon fruit\n   - On your way back, pick up the Survival Guide at H/I-5 if you have yet to get it.\n4. Return to the Stone monument for another CS.\n5. Examine the Sunken Hollow at (G-7) for a cutscene.\n6. Examine it again to enter a BCNM in Ghoyu\'s Reverie.\n7. The object of this BCNM is to escort both Nhev Befrathi and Syu Befrathi to the exit.\n   - Both mother and daughter can be escorted separately.\n   - The daughter walks extremely slow, however if she gets too close to any monster inside she will run away very quickly.\n   - The daughter will also run away if she\'s too far from the mother, regardless if you\'re close to her.\n     - It\'s recommended to slay all enemies on the path to the next map, bring the two just at the border of the next map, then do it again for all the crabs on the path. Note that the daughter will run WILDLY around the giant shells in the room with the Yagudo NINs, it is recommended slaying them and the far goblin near the shells. The mother, however, will NOT run clear across the room to path around them.\n   - The exit is located at (G-9) on map 2.  Both NPC\'s must be brought there. Upon success, you will be teleported out of the area.\n   - If you fail the BCNM, you will need to get another [Key Item]Succulent dragon fruit from the Succulent Cactus at (F-5). You can not obtain another [Key Item]Succulent dragon fruit until the folowing game day.\n8. When you finish the BCNM you appear in West Sarutabaruta (S) right next to the Windurst Waters (S) zone.\n9. Zone into Windurst Waters (S) for a CS and your reward.',
        notes = nil,
    },
    ['Snake on the Plains'] = {
        id = 8,
        start_npc = 'Miah Riyuh',
        start_zone = 'Windurst Waters',
        start_pos = 'H-9',
        description = 'Take a jar of Zonpa-Zippa\'s All-Purpose Putty to the stone towers in West Sarutabaruta (S)',
        reward = 'Bronze Ribbon of Service §\nSprinter\'s Shoes',
        fame = nil,
        fame_level = nil,
        title = 'Cobra Unit Mercenary',
        repeatable = nil,
        previous = nil,
        next = {'The Tigress Stirs'},
        requirements = nil,
        walkthrough = '1. Speak to Miah Riyuh. You will turn in the [Key Item]Green recommendation letter, and in exchange be given the [Key Item]Zonpa-Zippa\'s All-Purpose Putty to patch the to magical towers.\n   - This quest will change your Campaign allegiance. However, it has no cost or penalty as manually switching does.\n   - Speaking to Miah Riyuh before the conclusion of the quest will allow you to cancel it.\n2. Visit the 3 towers in West Sarutabaruta (S) at (F-4), (F-11), and (J-8) and touch the Sealed Entrance to apply the putty.\n3. Return to Miah Riyuh to complete the quest and become a member of the The Cobras. If this is your first initial quest to be completed, you will be given a pair of Sprinter\'s Shoes.',
        notes = nil,
