    ['Son and Father'] = {
        id = 57,
        start_npc = 'Exoroche',
        start_zone = 'Southern San d\'Oria',
        start_pos = 'K-9',
        description = 'A child stands crying by San d\'Oria Eastgate. Find his father for him.',
        reward = 'Trainee\'s Specs.',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = nil,
