    ['Succor to the Sidhe'] = {
        id = 55,
        start_npc = 'Callisto',
        start_zone = 'Grauberg (S)',
        start_pos = nil,
        description = 'To save their ancestral home from a fate of destruction, the fey folk would entreat your aid.',
        reward = 'Varies',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = nil,
        repeatable = 'Yes',
        previous = nil,
        next = nil,
        requirements = {
            {name = 'Varies', count = 1},
        },
        walkthrough = '1. First you need to obtain a base weapon to be augmented.  There\'s one weapon for each job:\n2. Trade one of the weapons to Callisto, Grauberg (S) (F-6).\n3. Find any of the Watchful Pixies located in one of the following Shadowreign zones and choose to begin the battle:\n4. Once the NM\'s are defeated, a Jubilant Pixie NPC will spawn.  Speak to the Jubilant Pixie and the weapon you traded to Callisto will be offered to you with random augments.\n   - If you do not like the augments you can choose to refuse to take the weapon, up to five attempts to get better augments.\n5. Details for augment are only sparsely documented online, and appear to differ per weapon.\n   - Notable possibilities include:\n     - +magic skill, added effect elemental damage, added effect status effects, enmity modifiers, +WSD (up to 5%), Store TP, DA/TA, Subtle Blow, Primary Stats, Song Spellcasting Time, Cure Potency, and certain Resist modifiers (1-5%).\n   - Availability of various augment possibilities definitely depends on job, and also possibly on zone and other factors.\n   - (With the right mods this could be useful with gear sets especially if used in a less important weapon slot, but since TP will be reset to zero, it would have to be done intelligently. Most players should probably not bother with this content in current-day retail.)',
        notes = nil,
    },
    ['The Dawn Also Rises'] = {
        id = 74,
        start_npc = 'Walk of Echoes (S)',
        start_zone = nil,
        start_pos = nil,
        description = 'Challenging Cait Sith again requires another visit to either Ronfaure, Jugner Forest, or Beaucedine Glacier in the Shadowreign Era to gather a breath of dawn.',
        reward = 'Choice of:\nPact with Cait Sith\n10,000 Gil',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = 'Light of Dawn',
        repeatable = 'Yes',
        previous = {'Champion of the Dawn'},
        next = nil,
        requirements = {
            {name = 'See walkthrough for details.', count = 1},
        },
        walkthrough = '1. Zone into Walk of Echoes\n   - Veridical Conflux at Grauberg (S) (F-5)\n   - or Veridical Conflux at Pashhow Marshlands (S) (J-9)\n   - or take the Survival Guide to Batallia Downs and click the ??? next to the maw to use your Lightsworm to enter.\n2. Select the Ornate Door up the stairs for a cutscene.\n3. Cait Sith asks you to find a remnant of latent energy. The latent energy points are found in the following locations:\n   - This quest is the same fight as the previous quest except that you only need one [Key Item] Breath of dawn.\n   - Beaucedine Glacier (S), there is an unlabeled (blank) point of interest down the hill on the border of G-9 and H-9. Select it for the [Key Item] Breath of dawn.\n   - East Ronfaure (S), northwest corner of H-7 by a tree alongside the river. Select it for the [Key Item] Breath of dawn.\n   - Jugner Forest (S), the southeast corner of Lake Mechieume has it, (I-6), just east of the river at the mouth of the lake. Select it for the [Key Item] Breath of dawn.\n     - Survival guide warp to East Ronfaure (S) then head east in Jugner Forest (S) is the fastest way.\n4. Take one of these three Key Items to Walk of Echoes through the Veridical Conflux at Grauberg (S) (F-5) or Pashhow Marshlands (S) (J-9) or using Lightsworm in Batallia Downs.\n5. Check the Ornate Door for a cut scene, and again to begin the fight.',
        notes = nil,
    },
