    ['The Long March North'] = {
        id = 46,
        start_npc = 'Robel-Akbel',
        start_zone = 'Windurst Waters (S)',
        start_pos = nil,
        description = 'Battered but not beaten, the Windurstian army steels itself for a grueling march north. The first leg of the journey takes you to San d\'Oria, where you and your Cobra companions will learn what trouble lies brewing on the Valdeaunian front.',
        reward = 'Stellar Earring',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'A Feast for Gnats'},
        next = {'The Forbidden Path'},
        requirements = nil,
        walkthrough = '1. Zone into Windurst Waters (S) for a cutscene.\n2. Go to Southern San d\'Oria (S) and talk to Raustigne (I-7) for a cutscene.\n   - Lehko Habhoka mentions the need for [Key Item] Darkfire cinders and [Key Item] Floelight stones, although you will not obtain the latter.\n3. Talk to Hauberliond (H-9) for a cutscene.\n4. Depending on your answers, you will be instructed to find New-turned Earth in one of three zones:\n   - East Ronfaure (S) at (J-11), this is near the Survival Guide.\n   - La Vaule (S) at (K-9).\n     - On the rock between the hut and the wooden stable. They may not appear if there is a campaign there. If you cannot see it, sign up and butcher the campaign enemies so they leave.\n     - This appears to be the result if you choose the top answers only.\n   - Jugner Forest (S) at (J-5) (near Batallia Downs (S)\'s Survival Guide).\n5. Check the New-turned Earth for a cutscene and [Key Item]Darkfire Cinder.\n6. Head to the Metalworks  Gunpowder Room (present day) and talk to Striking Snake (H-7) for a cutscene.\n7. Grab some pickaxes.\n8. Head to North Gustaberg (S) locate Mining points to obtain [Key Item]Liquid Quicksilver and [Key Item]Gelid Sulfur.\n   - It\'s possible to get both from the same Mining Point.\n9. Return to Striking Snake with both key items for a brief cutscene.\n   - You must now wait 1 game day and change zones.\n10. Talk to Striking Snake after zoning and waiting 1 game day to receive [Key Item]Beastbane Bullets.\n11. Head to Fort Karugo-Narugo (S) and talk to Rotih Moalghett (I-8) on map 2 for a cutscene.\n12. Head to (E/F-7) and examine the Warding Door to start a fight.\n   - Note: The battle will begin as soon as you click on the door; there is no cutscene.\n   - There is a 30 minute time limit for this fight.\n   - The battle is against 5 monsters:\n     - Count Furfur:  Appears to be a Dark Knight.\n     - Count Murmur x2: Appear to be Warriors.\n     - Tartalo x2 (Ahriman): Appear to be Black Mages and love to cast -ga spells including Sleepga.\n   - Up to 6 people in one party may participate at once in this battle.\n   - Fight is trivial for any character at level 99.\n13. Once the monsters are defeated, check the Warding Door again at (E/F-7) for a final cutscene and Stellar Earring.\n   - If your inventory is full, check the Warding Door again for your reward. The cutscene will not be replayed.',
        notes = nil,
    },
    ['The Lost Book'] = {
        id = 26,
        start_npc = 'Yoran-Oran',
        start_zone = 'Windurst Waters',
        start_pos = 'J-9',
        description = 'A book that Yoran-Oran borrowed from the Library of Magic was supposedly stolen and taken to Giddeus by the Yagudo.',
        reward = 'Retrace (Scroll)',
        fame = 'Crystal War',
        fame_level = nil,
