    ['The Truth Lies Hid'] = {
        id = 58,
        start_npc = 'Gentle Tiger',
        start_zone = 'Bastok Markets',
        start_pos = 'H-6',
        description = 'Klara Bester, erstwhile captain of the Mythril Musketeers turned fugitive, has ensconced herself deep in the heart of Castle Zvahl. You must infiltrate the enemy stronghold with your comrades and uncover the truth behind your ex-commander\'s treachery.',
        reward = 'Sanctus Rosary',
        fame = 'Wings of the Goddess',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'What Price Loyalty'},
        next = {'Bonds of Mythril'},
        requirements = {
            {name = ' Elixir', count = 1},
        },
        walkthrough = '1. Obtain an Elixir from the Curio Moogle or Auction House.\n2. Speak to Gentle Tiger in Bastok Markets (S) at (H-6) to begin the quest.\n3. Enter Castle Zvahl Baileys (S) for a cutscene.\n4. In Castle Zvahl Keep (S), there are three Imp NPCs.\n   - Rikke is the northwest Imp at (G-7) on the first map.\n   - Rakke is the southwest Imp at (G-10) on the first map.\n   - Rokke is the southeast Imp at (H-10) on the first map.\n5. Speak to all three imps, they will each demand an Elixir. Your goal is to determine which one is telling the truth.\n   - You do not need to trade the Elixir to make them talk, you only trade it when you know which to give it to.\n   - Each Imp will make a statement regarding another imp being honest or dishonest. Pay close attention to the line(s) immediately after the Elixir request.\n   - You don\'t need to speak to all three imps (but you may be forced to). It is possible to deduce the correct imp from talking to just one or two.\n   - See the Discussion page for detailed answers.\n6. Trade the Elixir to the proper Imp NPC to get a cutscene explaining where you need to go to next.\n   - Whether you\'re right or wrong, the Elixir is not consumed. However, if you choose incorrectly, you must wait until the next game-day (zoning not necessary) and speak with the imps again to figure out which imp is the correct one. It may have changed from the previous day.\n7. Examine the ??? in the south-west room (G-9) on the third map (the map with the teleporters) for a cutscene.\n8. Drop down and use the center teleporter, then examine the Displaced Block for another cutscene and your reward.',
        notes = nil,
    },
